def generate_full_content():
    # --- 1. DALAIL GENERATION ---
    src_awrad = 'app/src/main/assets/data/awrad.json'
    if os.path.exists(src_awrad):
        with open(src_awrad, 'r', encoding='utf-8') as f:
            awrad_list = json.load(f)
        
        dalail_titles = {
            "saturday": "Шанба вирди",
            "sunday": "Якшанба вирди",
            "monday": "Душанба вирди",
            "tuesday": "Сешанба вирди",
            "wednesday": "Чоршанба вирди",
            "thursday": "Пайшанба вирди",
            "friday": "Жума вирди"
        }

        final_dalail = []
        for item in awrad_list:
            item_id = item['id']
            # Map generic keys to specific variables if needed
            trans = dalail_translations.get(item_id, "")
            
            if not trans:
                trans = "[Таржимаси тайёрланмоқда]"
            
            # Use Uzbek title if available, else fallback to existing
            title_uz = dalail_titles.get(item_id, item.get('title', ''))

            final_item = {
                "id": item_id,
                "day": item.get('day', ''),
                "type": "dua",
                "title": title_uz, 
                "content": trans,   # Uzbek in content to avoid duplication
                "translation": ""   # Empty translation
            }
            final_dalail.append(final_item)
            
        os.makedirs('app/src/main/assets/uz', exist_ok=True)
        with open('app/src/main/assets/uz/dalail.json', 'w', encoding='utf-8') as f:
            json.dump(final_dalail, f, ensure_ascii=False, indent=2)
        print("Generated uz/dalail.json")

    # --- 2. MUNAJAT GENERATION ---
    src_munajat = 'app/src/main/assets/data/munajat.json'
    if os.path.exists(src_munajat):
        with open(src_munajat, 'r', encoding='utf-8') as f:
            munajat_list = json.load(f)
        
        final_munajat = []
        for item in munajat_list:
            item_id = item['id']
            trans = munajat_translations.get(item_id, "")
            if not trans:
                trans = "[Таржимаси тайёрланмоқда]" 

            title_uz = munajat_titles_uz.get(item_id, item.get('title', ''))

            final_item = {
                "id": item_id,
                "type": "dua",
                "title": title_uz,
                "content": trans,    # Uzbek in content
                "translation": ""    # Empty translation
            }
            final_munajat.append(final_item)

        with open('app/src/main/assets/uz/munajat.json', 'w', encoding='utf-8') as f:
            json.dump(final_munajat, f, ensure_ascii=False, indent=2)
        print("Generated uz/munajat.json")
    
    # --- 3. HISN GENERATION ---
    src_hisn = 'app/src/main/assets/data/hisn.json'
    if os.path.exists(src_hisn):
        with open(src_hisn, 'r', encoding='utf-8') as f:
            structure = json.load(f)
        
        final_hisn = []
        for category in structure:
            new_cat = category.copy()
            new_cat['items'] = []
            
            # Translate category title if possible (simple map)
            # Keys must match JSON ids: hisn_morning, hisn_evening, etc.
            cat_map = {
                "hisn_morning": "Тонгги зикрлар",
                "hisn_evening": "Кечки зикрлар",
                "hisn_sleep": "Уйқу зикрлари",
                "hisn_prayer": "Намоз зикрлари",
                "hisn_food": "Таомланиш зикрлари",
                "hisn_travel": "Сафар зикрлари",
                "hisn_mosque": "Масжид зикрлари"
            }
            if new_cat['id'] in cat_map:
                new_cat['title'] = cat_map[new_cat['id']]

            for item in category['items']:
                item_id = item['id']
                trans_text = hisn_translations.get(item_id, "")
                
                final_item = item.copy()
                
                # Logic: Keep Arabic in content (or arabic field), put Uzbek in translation.
                # Matching English structure: Content/Arabic = Arabic text, Translation = Uzbek text.
                
                # Ensure content is populated with Arabic (source usually has 'arabic')
                if 'arabic' in item:
                    final_item['content'] = item['arabic']
                    # Keep 'arabic' field as well just in case
                else:
                    # Fallback if no arabic field
                    final_item['content'] = item.get('content', '')

                # Set translation and fadl
                if trans_text:
                    # Check for Fadl (Virtue) separator
                    if "Фазилати:" in trans_text:
                        parts = trans_text.split("Фазилати:", 1)
                        final_item['translation'] = parts[0].strip()
                        final_item['fadl'] = parts[1].strip()
                    else:
                        final_item['translation'] = trans_text.strip()
                        # If no Uzbek fadl exists, but original has it, we might want to empty it 
                        # to avoid showing Arabic/English object in UI, or keep it empty string.
                        # Setting it to empty string is safer ensuring clean Uzbek UI.
                        final_item['fadl'] = ""
                else:
                    final_item['translation'] = "" 
                    final_item['fadl'] = "" # Ensure no residue
                
                new_cat['items'].append(final_item)
            final_hisn.append(new_cat)

        with open('app/src/main/assets/uz/hisn.json', 'w', encoding='utf-8') as f:
            json.dump(final_hisn, f, ensure_ascii=False, indent=2)
        print("Generated uz/hisn.json")

    # --- 4. STATIC GENERATION ---
    with open('app/src/main/assets/uz/static.json', 'w', encoding='utf-8') as f:
        json.dump(static_data, f, ensure_ascii=False, indent=2)
    print("Generated uz/static.json")

if __name__ == "__main__":
    generate_full_content()
